oxy_webhelp_navlinks = {"tocId-d30753e20453":{"topics":[{"title":"Azure SQL native backup capabilities","shortdesc":"<p class=\"shortdesc\">Azure provides native backup solutions for Azure SQL workloads, including         Point-in-Time Retention and Long-Term Retention. While these offer foundational protection,         they have certain limitations.<\/p>","href":"saas\/azr_sql_native_backup_capability.html","attributes":{"data-id":"azr_sql_native_backup_capability"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_backup_capability-d30753e20454","topics":[]},{"title":"Azure SQL native versus Rubrik backups","shortdesc":"<p class=\"shortdesc\">A comparative overview of Azure-native backup policies and Rubrik backups for         Azure SQL workloads.<\/p>","href":"saas\/azr_sql_native_vs_rbk_backups.html","attributes":{"data-id":"azr_sql_native_vs_rbk_backups"},"menu":{"hasChildren":false},"tocID":"azr_sql_native_vs_rbk_backups-d30753e20465","topics":[]},{"title":"Independent SLA support for Rubrik and Azure backups","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> provides independent SLA Domain support for Rubrik backups and         Azure-native backups, enabling both to coexist within the same environment.<\/p>","href":"saas\/azr_sql_independent_sla_support.html","attributes":{"data-id":"azr_sql_independent_sla_support"},"menu":{"hasChildren":false},"tocID":"azr_sql_independent_sla_support-d30753e20476","topics":[]},{"title":"Supported Azure SQL backup and recovery types","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Databases and Managed Instances by supporting         different types of backup and recovery options.<\/p>","href":"saas\/azr_sql_supp_backup_recv_types.html","attributes":{"data-id":"azr_sql_supp_backup_recv_types"},"menu":{"hasChildren":false},"tocID":"azr_sql_supp_backup_recv_types-d30753e20489","topics":[]},{"title":"Rubrik backup components for Azure SQL DB","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> protects Azure SQL Databases by taking Rubrik backups that use         several key components: Rubrik Exocompute for data processing, the Cloud Storage Layer for         efficient storage, and snapshot immutability for cyber resilience. These backups offer         significant advantages, including a logical air gap and flexible recovery         options.<\/p>","href":"saas\/azr_sql_db_rbk_backup_components.html","attributes":{"data-id":"azr_sql_db_rbk_backup_components"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_rbk_backup_components-d30753e20502","topics":[]},{"title":"Supported datatypes for Azure SQL DB Rubrik backups","shortdesc":"<p class=\"shortdesc\">Information about the datatypes that <span class=\"ph\">RSC<\/span> supports for the Azure SQL         Database Rubrik backups.<\/p>","href":"saas\/azr_sql_db_supp_datatypes_rbk_backup.html","attributes":{"data-id":"azr_sql_db_supp_datatypes_rbk_backup"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_supp_datatypes_rbk_backup-d30753e20515","topics":[]},{"title":"Support for Azure SQL TDE with customer-managed keys","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> supports the backup and recovery of Azure SQL Databases encrypted         using Transparent Data Encryption with Customer-Managed Keys.<\/p>","href":"saas\/azure_sql_tde_support.html","attributes":{"data-id":"azure_sql_tde_support"},"menu":{"hasChildren":false},"tocID":"azure_sql_tde_support-d30753e20529","topics":[]},{"title":"Azure SQL DB Rubrik backup limitations","shortdesc":"<p class=\"shortdesc\">Rubrik backup and recovery of Azure SQL Databases has certain limitations.<\/p>","href":"saas\/azr_sql_db_rbk_backup_limitations.html","attributes":{"data-id":"azr_sql_db_rbk_backup_limitations"},"menu":{"hasChildren":false},"tocID":"azr_sql_db_rbk_backup_limitations-d30753e20542","topics":[]}]}};